@@ -81,4 +81,27 @@ describe("extractEmbeddedRoot", () => {
 		expect(await readFile(join(newRootDir, "root.md"), "utf-8")).toBe("# New Root\n");
 		expect(await Bun.file(join(newRootDir, "sentinel.txt")).exists()).toBe(false);
